"""
MKT Original — Matthew 27–28
Output: data/commentary/mkt-original/matthew.json (adds ch27-28; completes Matthew)
"""
import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: Per-verse Greek lexical commentary for Matthew 27-28; covers the
#   Crucifixion, Death, Burial, Resurrection, and Great Commission. Strictly lexical.
# CHANGE? If verse keys change in data/interlinear/matthew.json, update dict keys here.
# VERIFY: Run script; confirm "wrote data/commentary/mkt-original/matthew.json".
#   Then check ch27 = 66 verses, ch28 = 20 verses.

NEW_DATA = {
  "27": {
    "1": "<p><strong>prōias de genomenes symbo ulion elabon pantes hoi archiereis kai hoi presbyteroi</strong> — <em>when morning came all the chief priests and elders took counsel</em> — <em>Prōias de genomenes</em> (morning having come, genitive absolute) — after the night trial a formal daytime session is required for a legally valid Sanhedrin capital verdict. <em>Symbolion elabon</em> (took counsel, formed a plan) — <em>symbolion</em> (council, deliberation) — the formal morning ratification of the nocturnal vote.</p>",
    "2": "<p><strong>kai dēsantes auton apēgagon kai paredōkan Pilatō̄ tō̄ hēgemoni</strong> — <em>and binding him they led him away and handed him over to Pilate the governor</em> — <em>Dēsantes</em> (having bound, aorist participle) — binding a prisoner for transport. <em>Apēgagon</em> (led away) and <em>paredōkan</em> (handed over) — the two passion verbs in sequence. <em>Hēgemōn</em> (governor, one who leads) = the Roman prefect\xe2\x80\x99s title; Pilate served as prefect of Judea AD 26-36.</p>",
    "3": "<p><strong>tote idōn Ioudas ho paradous auton hoti katekrithē metamelētheis</strong> — <em>then Judas who had betrayed him seeing that he was condemned felt remorse</em> — <em>Metamelomai</em> (to feel regret, to have a change of feeling — not the same as <em>metanoeō</em>: repentance leading to restoration). The aorist passive <em>katekrithē</em> (was condemned) — Judas did not anticipate this outcome. <em>Estrēpsen ta triakonta argyria</em> (brought back the thirty silver pieces) — <em>strephō</em> (to turn, return) the coins.</p>",
    "4": "<p><strong>hēmarton paradous haima athō̄on</strong> — <em>I sinned betraying innocent blood</em> — <em>Hēmarton</em> (I sinned, aorist) — a confession of sin. <em>Haima athō̄on</em> (innocent blood — <em>athō̄os</em> = without penalty, guiltless) is a legal and theological term; shedding innocent blood incurred divine judgment (Deut 19:10; 1 Kgs 2:31). <em>Ti pros hēmas sy opsei</em> (what is that to us? See to it yourself) — the leaders\xe2\x80\x99 dismissal is callous legal language.</p>",
    "5": "<p><strong>kai rhipsas ta argyria eis ton naon anechōrēsen</strong> — <em>throwing the silver into the sanctuary he departed</em> — <em>Rhipsas</em> (having thrown, cast) — a violent gesture of rejection. <em>Eis ton naon</em> (into the sanctuary/inner temple) — only priests could enter; Judas throws the coins from outside into the sacred space. <em>Apelthōn apēgxato</em> (departed and hanged himself) — <em>apagchomai</em> (to strangle oneself, hang oneself) — cf. Acts 1:18\xe2\x80\x99s different account of the death.</p>",
    "6": "<p><strong>hoi de archiereis labontes ta argyria eipan</strong> — <em>the chief priests taking the silver said</em> — <em>Ouk exestin balein auta eis ton korbōnan</em> (it is not lawful to throw them into the treasury) — <em>korbōnas</em> (the temple treasury — from Hebrew <em>qorban</em> = offering dedicated to God). The irony: they have no scruple about paying for innocent blood but scruple about returning the money to God\xe2\x80\x99s treasury. <em>Epei timē haimatos estin</em> (since it is the price of blood).</p>",
    "7": "<p><strong>symbo ulion de labontes ēgorasan ex autōn ton agron tou kerameos</strong> — <em>taking counsel they bought with them the potter\xe2\x80\x99s field</em> — <em>Agros tou kerameos</em> (the potter\xe2\x80\x99s field) — a clay-rich plot used for pottery manufacture, purchased for <em>taphēn tois xenois</em> (burial of strangers/foreigners). The leaders\xe2\x80\x99 decision ironically fulfills prophecy through their own initiative.</p>",
    "8": "<p><strong>dio eklēthē ho agros ekeinos Agros Haimatos heōs tēs sēmeron</strong> — <em>therefore that field was called Field of Blood until today</em> — <em>Agros Haimatos</em> = Hakeldama (Aramaic, Acts 1:19). The <em>heōs tēs sēmeron</em> (until today) formula marks an etiology — explaining a place-name by its origin story, a common OT narrative device.</p>",
    "9": "<p><strong>tote eplērōthē to rhēthen dia Ieremiou tou prophētou</strong> — <em>then was fulfilled what was spoken through Jeremiah the prophet</em> — The attribution to Jeremiah is puzzling; the citation conflates Zech 11:12-13 with Jer 18-19 (the potter\xe2\x80\x99s field/Hinnom Valley imagery). Some scholars suggest <em>Ieremiou</em> is a scribal error for <em>Zachariou</em>; others note Jeremiah\xe2\x80\x99s purchase of a field (Jer 32) as the deeper background. Matthew\xe2\x80\x99s LXX-influenced citation is a composite prophecy.</p>",
    "10": "<p><strong>kai edōkan auta eis ton agron tou kerameos kathōs synetaxen moi kyrios</strong> — <em>and gave them for the potter\xe2\x80\x99s field as the Lord directed me</em> — <em>Kathōs synetaxen moi kyrios</em> (as the Lord directed/commanded me) — citing the prophetic word as divine directive. The fulfillment formula closes the Judas-Akeldama parenthesis and returns to the Roman trial narrative.</p>",
    "11": "<p><strong>ho de Iēsous estathē emprosthen tou hēgemonos</strong> — <em>Jesus stood before the governor</em> — <em>Estathē</em> (aorist passive of <em>histēmi</em>: was placed, stood) — the accused presented before the magistrate. <em>Sy ei ho basileus tōn Ioudaiōn</em> (are you the king of the Jews?) — Pilate\xe2\x80\x99s question shifts from the Jewish blasphemy charge to the Roman sedition charge: king-claiming. <em>Sy legeis</em> (you say so) — the same affirming formula as 26:25,64.</p>",
    "12": "<p><strong>kai en tō̄ katēgoreisthai auton hypo tōn archiereōn kai presbyterōn ouden apekrithē</strong> — <em>while being accused by the chief priests and elders he answered nothing</em> — <em>Katēgoreisthai</em> (present passive infinitive of <em>katēgoreō</em> = to accuse — the legal term giving us English \xe2\x80\x9ccategory\xe2\x80\x9d via \xe2\x80\x9caccusation\xe2\x80\x9d). <em>Ouden apekrithē</em> (answered nothing) — the silence of Isa 53:7 continues in the Roman proceedings.</p>",
    "13": "<p><strong>tote legei autō̄ ho Pilatos ouk akoueis posa sou katamartyrousi</strong> — <em>then Pilate says: do you not hear how many things they testify against you?</em> — <em>Posa</em> (how many things, how much) — the number and weight of charges. Pilate\xe2\x80\x99s question implies surprise at the silence; Roman legal procedure expected a defense. <em>Katamartyrousi</em> (testify against, bear witness against — <em>kata</em> = against + <em>martyreō</em>).</p>",
    "14": "<p><strong>kai ouk apekrithē autō̄ pros oude hen rhēma</strong> — <em>he did not answer him even one word</em> — <em>Pros oude hen rhēma</em> (not even one word) — the absolute totality of the silence. <em>Hōste thaumazein ton hēgemona lian</em> (so that the governor marveled greatly) — <em>lian</em> (greatly, exceedingly) — Pilate\xe2\x80\x99s astonishment. Roman magistrates were experienced with defendants who argued vigorously; Jesus\xe2\x80\x99 silence was extraordinary.</p>",
    "15": "<p><strong>kata de heortēn eiōthei ho hēgemōn apolyein hena tō̄ ochlō̄ desmion</strong> — <em>at the feast the governor was accustomed to release one prisoner to the crowd</em> — <em>Eiōthei</em> (was accustomed — pluperfect of <em>ethō</em>: was in the habit of, customarily did) — an established Passover custom. No external Roman documentation confirms this practice; it may be a local accommodation or a Passover amnesty arrangement.</p>",
    "16": "<p><strong>eichon de tote desmion episēmon legomenon Barabbān</strong> — <em>they had at that time a notorious prisoner called Barabbas</em> — <em>Episēmos</em> (notable, notorious — from <em>epi</em> + <em>sēma</em> = marked, distinguished; can be positive or negative) — here clearly negative: a notable criminal. <em>Barabbās</em> = Aramaic <em>bar-ʾabbāʾ</em> (son of the father) — the ironic name-contrast with Jesus Son of the Father.</p>",
    "17": "<p><strong>tina thelete apolysō hymin</strong> — <em>whom do you wish I release to you?</em> — Pilate\xe2\x80\x99s question frames the choice explicitly. <em>Ton Barabbān ē Iēsoun ton legomenon christon</em> (Barabbas or Jesus who is called Christ) — <em>ton legomenon christon</em> (the one called Christ) — Pilate\xe2\x80\x99s own framing names Jesus by his Messianic title, underscoring the choice between political insurgency and the claimed Messiah.</p>",
    "18": "<p><strong>ē̄dei gar hoti dia phthonon paredōkan auton</strong> — <em>for he knew that out of envy they had handed him over</em> — <em>Phthonos</em> (envy, malice — the desire to deprive another of good) — Pilate perceives the real motive behind the chief priests\xe2\x80\x99 pressure. <em>Ē̄dei</em> (pluperfect of <em>oida</em>: had known, was aware) — Pilate\xe2\x80\x99s knowledge of the politics.</p>",
    "19": "<p><strong>kathēmenou de autou epi tou bēmatos apesteilen pros auton hē gynē autou</strong> — <em>while he was sitting on the judgment seat his wife sent to him</em> — <em>Bēma</em> (judgment seat, tribunal — the elevated platform from which a Roman magistrate dispensed justice). The wife\xe2\x80\x99s message is unique to Matthew: <em>mēden soi kai tō̄ dikaiō̄ ekeinō̄</em> (have nothing to do with that righteous man) — <em>dikaios</em> (righteous, just) — an outsider\xe2\x80\x99s recognition of Jesus\xe2\x80\x99 innocence.</p>",
    "20": "<p><strong>hoi de archiereis kai hoi presbyteroi epeisan tous ochlous</strong> — <em>the chief priests and elders persuaded the crowds</em> — <em>Epeisan</em> (aorist of <em>peithō</em> = to persuade, convince) — the leaders actively worked the crowd. <em>Hina aitēsōntai ton Barabbān ton de Iēsoun apolēsōsin</em> (to ask for Barabbas and destroy Jesus) — <em>apolēsōsin</em> (aorist subjunctive of <em>apollymi</em> = to destroy, kill).</p>",
    "21": "<p><strong>tina thelete apo tōn dyo apolysō hymin</strong> — <em>which of the two do you wish I release to you?</em> — Pilate\xe2\x80\x99s repeated offer; <em>hoi de eipan ton Barabbān</em> (they said: Barabbas) — the crowd\xe2\x80\x99s choice is blunt and unqualified. The answer requires no deliberation; the crowd\xe2\x80\x99s demand is immediate.</p>",
    "22": "<p><strong>ti oun poiēsō Iēsoun ton legomenon christon</strong> — <em>what then shall I do with Jesus who is called Christ?</em> — Pilate\xe2\x80\x99s question frames the crowd as co-decision-makers. <em>Legousin pantes staurōthētō</em> (they all say: let him be crucified) — <em>staurōthētō</em> (aorist passive imperative of <em>stauroō</em> = crucify him) — third-person imperative demanding execution by Roman means (crucifixion was not a Jewish method of execution).</p>",
    "23": "<p><strong>ho de ephē ti gar kakon epoiēsen</strong> — <em>he said: for what evil has he done?</em> — Pilate\xe2\x80\x99s direct challenge for evidence of wrongdoing. <em>Hoi de perissos ekrāzōn legontes staurōthētō</em> (they cried out all the more saying: crucify him) — <em>perissōs</em> (exceedingly, beyond measure) + <em>ekrazon</em> (imperfect: kept crying out) — escalating, sustained crowd pressure.</p>",
    "24": "<p><strong>idōn de ho Pilatos hoti ouden ōphelei alla mallon thorybos ginetai</strong> — <em>Pilate seeing that he was accomplishing nothing but rather a riot was developing</em> — <em>Ōphelei</em> (accomplishes, benefits — present indicative: nothing is being achieved by his resistance). <em>Thorybos ginetai</em> (a riot is forming) — the political calculus shifts. <em>Labōn hydōr apenipsato tas cheiras</em> (taking water he washed his hands) — <em>aponiptō</em> (to wash off) — a Jewish gesture of disavowal (Deut 21:6-9; Ps 26:6).</p>",
    "25": "<p><strong>kai apokritheis pas ho laos eipen to haima autou eph\' hēmas kai epi ta tekna hēmōn</strong> — <em>all the people answered: his blood on us and on our children</em> — <em>Pas ho laos</em> (all the people) — a corporate acceptance of blood-guilt. <em>To haima autou eph\' hēmas</em> (his blood upon us) — the biblical blood-responsibility formula (2 Sam 1:16; Josh 2:19). Historically this verse has been abused for anti-Semitic ends; the formula is a self-imprecation by a specific crowd at a specific moment, not an eternal curse on all Jewish people.</p>",
    "26": "<p><strong>tote apelysen autois ton Barabbān ton de Iēsoun phragellosās paredōken hina staurōthē̄</strong> — <em>then he released Barabbas, and having flogged Jesus he handed him over to be crucified</em> — <em>Phragellosās</em> (having flogged — from Latin <em>flagellum</em>: the Roman scourge with bone/metal tips) — a brutal preliminary punishment, often fatal on its own. <em>Paredōken hina staurōthē̄</em> (handed over so that he would be crucified) — final judicial handover.</p>",
    "27": "<p><strong>tote hoi stratiōtai tou hēgemonos paralabontes ton Iēsoun eis to praitōrion</strong> — <em>then the soldiers of the governor taking Jesus into the praetorium</em> — <em>Praitōrion</em> (the governor\xe2\x80\x99s headquarters — from Latin <em>praetorium</em>): either Herod\xe2\x80\x99s palace in the upper city or the Antonia fortress. <em>Synēgagon ep\' auton holēn tēn speiran</em> (assembled the whole cohort against him) — <em>speira</em> (cohort = 1/10 legion, ~600 men; sometimes used for smaller detachments).</p>",
    "28": "<p><strong>kai ekdysantes auton chlamyda kokkinēn periethekan autō̄</strong> — <em>stripping him they put around him a scarlet robe</em> — <em>Ekdysantes</em> (stripping, undressing — prior to flogging, garments were removed). <em>Chlamy da kokkinēn</em> (a scarlet robe) — a military/officer\xe2\x80\x99s cloak, mimicking the purple of royalty in mockery. <em>Periethekan</em> (put around him) — the mock-investiture.</p>",
    "29": "<p><strong>kai plexantes stephanon ex akanthōn epethēkan epi tēs kephalēs autou</strong> — <em>plaiting a crown of thorns they placed it on his head</em> — <em>Plexantes</em> (plaiting, weaving together) — a crown (<em>stephanos</em> = victor\xe2\x80\x99s wreath, not <em>diadēma</em> = royal crown) of thorns twisted together. <em>Kalamōn en tē̄ dexiā̧ autou</em> (a reed in his right hand) — a mock scepter. <em>Gonypetēsantes emprosthen autou enepaixan autō̄</em> (kneeling before him they mocked him) — the gesture of homage becomes mockery.</p>",
    "30": "<p><strong>kai emptysantes eis auton elabon ton kalamōn kai etypton eis tēn kephalēn autou</strong> — <em>spitting on him they took the reed and struck his head</em> — <em>Emptysantes</em> (having spat on him) — repeated spitting as in 26:67. <em>Etypton</em> (imperfect: kept striking) — the reed drives the thorns deeper. The scene enacts the servant\xe2\x80\x99s suffering of Isa 50:6 (<em>ton nōton mou edōka eis mastigas kai tas siagonas mou eis rapisma</em>) and 53:3.</p>",
    "31": "<p><strong>kai hote enepaixan autō̄ exedysan auton tēn chlamyda</strong> — <em>when they had mocked him they stripped the robe from him</em> — <em>Ekdyō</em> (to strip off, undress) — restoring his own garments before the crucifixion. <em>Kai apēgagon auton eis to staurōsai</em> (and led him away to crucify him) — <em>eis to staurōsai</em> (for the purpose of crucifying) — the infinitive of purpose.</p>",
    "32": "<p><strong>exerchomenoi de heuron anthrōpon Kyrēnaion onomati Simōna</strong> — <em>going out they found a Cyrenian man named Simon</em> — <em>Kyrēnaios</em> (Cyrenian = from Cyrene in North Africa, modern Libya) — the significant Jewish community in Cyrene made Passover pilgrims from there common. <em>Ton ēngareusan hina arē̄ ton stauron autou</em> (they impressed him to carry his cross) — <em>angareuō</em> (to impress into service, to compel to carry) — from Persian <em>angaros</em> (courier), used for the state\xe2\x80\x99s right to conscript labor.</p>",
    "33": "<p><strong>kai elthontes eis topon legomenon Golgotha</strong> — <em>coming to a place called Golgotha</em> — <em>Golgotha</em> is the Aramaic transliteration of <em>gulgaltā</em> (skull); the Greek rendering <em>Kranion Topos</em> (Place of a Skull) gives Latin <em>Calvaria</em>. Whether this refers to a skull-shaped hill or a site of execution-related skulls is debated; the location is northwest of the city.</p>",
    "34": "<p><strong>edōkan autō̄ pieīn oxos meta cholēs memeigmenon</strong> — <em>they gave him wine mixed with gall to drink</em> — <em>Oxyos meta cholēs memeigmenon</em> (wine/vinegar mixed with gall) — <em>cholē</em> (bile, gall — a bitter substance) echoes Ps 69:21 LXX (<em>kai edōkan eis to brōma mou cholēn</em>). Mark 15:23 has <em>smyrnismenon oinon</em> (wine mixed with myrrh) — a painkiller; Matthew\xe2\x80\x99s <em>cholē</em> emphasizes the bitterness and OT fulfillment.</p>",
    "35": "<p><strong>staurōsantes de auton diemerisanto ta himatia autou ballon klēron</strong> — <em>crucifying him they divided his garments by casting lots</em> — <em>Staurōsantes</em> (crucifying — aorist participle used absolutely, describing the primary act). <em>Diemerisanto ta himatia</em> (divided the garments) + <em>ballon klēron</em> (casting lots) = Ps 22:18 LXX verbatim (<em>diemerisanto ta himatia mou heautois kai epi ton himatismon mou ebalon klēron</em>).</p>",
    "36": "<p><strong>kai kathēmenoi etēroun auton ekei</strong> — <em>and sitting they kept watch over him there</em> — <em>Etēroun</em> (imperfect: kept watching) — the Roman soldiers\xe2\x80\x99 guard duty. The imperfect describes sustained action through the crucifixion hours. This detail confirms Roman military execution and prevents any premature removal from the cross.</p>",
    "37": "<p><strong>kai epethēkan epanō tēs kephalēs autou tēn aitian autou gegrammēnēn</strong> — <em>and placed above his head the charge against him written</em> — <em>Aitia</em> (charge, accusation, cause — the <em>titulus</em> nailed above the condemned person stating the crime). <em>Houtos estin Iēsous ho basileus tōn Ioudaiōn</em> (this is Jesus the King of the Jews) — the charge is also the ironic proclamation of his true identity.</p>",
    "38": "<p><strong>tote staurountai syn autō̄ dyo lē̄stai</strong> — <em>then two bandits are crucified with him</em> — <em>Lē̄stai</em> (bandits, robbers, insurgents — cf. 26:55) placed on either side (<em>heis ek dexiōn kai heis ex euōnymōn</em> = one on the right and one on the left), fulfilling Isa 53:12 (<em>en tois anomois elogisthē</em> = he was counted among the lawless).</p>",
    "39": "<p><strong>hoi de paraporeuomenoi eblasphēmoun auton kinountes tas kephalas autōn</strong> — <em>those passing by were blaspheming him wagging their heads</em> — <em>Kinountes tas kephalas</em> (wagging/shaking their heads) = the gesture of scorn and mockery from Ps 22:7 LXX (<em>eplēmmēlēsan en cheilesin, ekinēsan kephalēn</em>). <em>Blaspheō</em> (to slander, revile, blaspheme) — the same word used for the high priest\xe2\x80\x99s accusation against Jesus (26:65).</p>",
    "40": "<p><strong>ho katalyōn ton naon kai en trisin hēmerais oikodomōn</strong> — <em>you who would tear down the sanctuary and in three days rebuild it</em> — The temple charge from the false witnesses (26:61) is thrown back as a taunt. <em>Sōson seauton ei huios ei tou theou kai katabēthi apo tou staurou</em> (save yourself if you are Son of God, come down from the cross) — the <em>ei huios ei tou theou</em> (if you are Son of God) echoes the devil\xe2\x80\x99s temptation pattern (4:3,6).</p>",
    "41": "<p><strong>homoiōs kai hoi archiereis empaizōn meta tōn grammateōn kai presbyterōn elepāon</strong> — <em>similarly the chief priests mocking with the scribes and elders said</em> — <em>Empaizō</em> (to mock, play with, make sport of) — present participle describing ongoing mockery. All three groups (priests, scribes, elders) now appear together as in the trial scene, providing comprehensive institutional repudiation.</p>",
    "42": "<p><strong>allous esōsen heauton ou dynatai sōsai</strong> — <em>others he saved; himself he cannot save</em> — The taunt is dramatically ironic: the truth about saving others is conceded, and the inability to save himself is precisely the means by which he saves others. <em>Basileus Israēl estin katabatō nyn apo tou staurou kai pisteusōmen ep\' auton</em> (he is King of Israel; let him come down now from the cross and we will believe in him).</p>",
    "43": "<p><strong>pepoithen epi ton theon rhysasthō nyn ei thelei auton</strong> — <em>he trusted in God; let him rescue him now if he wants him</em> — <em>Pepoithen</em> (perfect of <em>peithō</em>: has trusted and trusts) — citing Ps 22:8 LXX (<em>ēlpisen epi kyrion rhysasthō auton sōsatō auton hoti thelei auton</em>). The mockers quote the psalm that Jesus will himself pray at v.46.</p>",
    "44": "<p><strong>to d\' auto kai hoi lē̄stai hoi synstaurōthentes syn autō̄ ōneidizon auton</strong> — <em>the bandits crucified with him also reproached him in the same way</em> — <em>Ōneidizon</em> (imperfect: were reproaching, taunting) — both bandits initially taunt; Luke 23:39-43 narrates the conversion of one. Matthew\xe2\x80\x99s summary form does not specify the later distinction.</p>",
    "45": "<p><strong>apo de hektēs hōras skotos egeneto epi pasan tēn gēn heōs hōras ennatēs</strong> — <em>from the sixth hour darkness came over all the land until the ninth hour</em> — <em>Skotos egeneto</em> (darkness occurred, came) — <em>epi pasan tēn gēn</em> (over all the land/earth) — the extent is unclear: all the land of Judea or the entire earth. The three-hour darkness (noon to 3 PM) echoes the Egyptian plague darkness (Ex 10:22) and Amos 8:9 (<em>kai dysetai ho hēlios mesēmbrias</em>).</p>",
    "47": "<p><strong>tines de tōn ekei hestēkotōn akousantes elegon hoti Ēlian phōnei houtos</strong> — <em>some of those standing there hearing said: this one is calling Elijah</em> — The mishearing of <em>Ēli</em> as <em>Ēlias</em> (Elijah) reflects either genuine mishearing in the chaos or deliberate misrepresentation. <em>Phōnei</em> (is calling, present tense — continuous cry) — the crowd interprets the cry of dereliction as an appeal to Elijah, the prophet associated with miraculous rescue.</p>",
    "48": "<p><strong>kai eutheōs dromōn heis ex autōn kai labōn spongon</strong> — <em>immediately one of them running and taking a sponge</em> — <em>Dromōn</em> (running — present participle of <em>trechō</em>, indicating urgency). <em>Plēsas te oxous kai peritheis kalamō̄ epotizen auton</em> (filling it with sour wine and putting it on a reed gave him to drink) — <em>oxos</em> (sour wine, vinegar — the soldiers\xe2\x80\x99 common drink, <em>posca</em>) fulfills Ps 69:21.</p>",
    "49": "<p><strong>hoi de loipoi elegon aphes idōmen ei erchetai Ēlias sōsōn auton</strong> — <em>the others said: wait, let us see whether Elijah comes to save him</em> — <em>Aphes</em> (leave, let be, wait) — the spectators hold back to observe whether the Elijah-rescue scenario materializes. The expectation of Elijah-rescue was part of popular eschatology; the watching crowd applies it as a test.</p>",
    "50": "<p><strong>ho de Iēsous palin kraxas phōnē̄ megalē̄ aphēken to pneuma</strong> — <em>Jesus again crying with a great voice released the spirit</em> — <em>Palin kraxas phōnē̄ megalē̄</em> (again crying with a great voice) — the physical ability to cry out loudly contradicts the typical physiological description of crucifixion death (asphyxiation). <em>Aphēken to pneuma</em> (released the spirit) — <em>aphiēmi</em> (to let go, release, dismiss) — a volitional act: Jesus yields his spirit rather than having it taken.</p>",
    "51": "<p><strong>kai idou to katapetasma tou naou eschisthē ap\' anōthen heōs katō eis dyo</strong> — <em>and behold the curtain of the sanctuary was torn from top to bottom in two</em> — <em>Katapetasma</em> (curtain, veil) — either the outer curtain (between court and Holy Place) or the inner veil (between Holy Place and Holy of Holies). <em>Ap\' anōthen heōs katō</em> (from top to bottom) — the tearing from above signals divine agency. <em>Kai hē gē eseisthē</em> (and the earth shook) — <em>seismōs megas</em> (great earthquake) accompanies the cosmic signs.</p>",
    "52": "<p><strong>kai ta mnēmeia aneōchthēsan kai polla sōmata tōn kekoimēmenōn hagiōn ēgerthēsan</strong> — <em>and the tombs were opened and many bodies of the saints who had fallen asleep were raised</em> — <em>Kekoimēmenōn hagiōn</em> (saints who had fallen asleep — perfect passive participle of <em>koimaomai</em> = to sleep, the NT euphemism for death). <em>Ēgerthēsan</em> (were raised, aorist passive) — this unique Matthean event has no parallel in other gospels and raises interpretive questions about its historical and theological status.</p>",
    "53": "<p><strong>kai exelthontes ek tōn mnēmeiōn meta tēn egersin autou eisēlthon eis tēn hagian polin</strong> — <em>and going out of the tombs after his resurrection they entered the holy city</em> — <em>Meta tēn egersin autou</em> (after his resurrection) — the raised saints emerge only after Jesus\xe2\x80\x99 resurrection, not immediately. This protects the <em>prōtotokos ek tōn nekrōn</em> (firstborn from the dead) primacy of Christ. <em>Enephanisthēsan pollois</em> (they appeared to many) — <em>emphanizō</em> (to make visible, manifest).</p>",
    "54": "<p><strong>ho de hekatontarchos kai hoi met\' autou tēroūntes ton Iēsoun</strong> — <em>the centurion and those with him keeping watch over Jesus</em> — <em>Hekatontarchos</em> (centurion, commander of 100) — the officer in charge of the execution. <em>Idōn ton seismon kai ta ginomena ephobēthēsan sphodra</strong> (seeing the earthquake and the things happening were greatly afraid). <em>Alēthōs theou huios ēn houtos</em> (truly this was Son of God) — a Gentile soldier\xe2\x80\x99s confession at the cross.</p>",
    "55": "<p><strong>ēsan de ekei gynaikes pollai apo makrothen theōrousai</strong> — <em>there were many women there watching from a distance</em> — <em>Theōrousai</em> (present active participle: watching, observing — <em>theōreō</em> implies careful attention). <em>Haitines ēkolouthēsan tō̄ Iēsou apo tēs Galilaias diakonousai autō̄</em> (who had followed Jesus from Galilee serving him) — <em>diakoneō</em> (to serve, minister) — the women\xe2\x80\x99s service parallels the angelic service of 4:11.</p>",
    "56": "<p><strong>en hais ēn Maria hē Magdalēnē kai Maria hē tou Iakōbou kai Iōsēph mētēr</strong> — <em>among whom was Mary Magdalene and Mary the mother of James and Joseph</em> — <em>Maria hē Magdalēnē</em> (Mary from Magdala on the western shore of Galilee) — prominent in all four Gospel resurrection accounts. <em>Kai hē mētēr tōn huiōn Zebedaiou</em> (and the mother of the sons of Zebedee) — Salome in Mark 15:40.</p>",
    "57": "<p><strong>opsias de genomenes ēlthen anthrōpos ploysios apo Harimathaias</strong> — <em>when evening came a wealthy man from Arimathea came</em> — <em>Plousios</em> (wealthy) — Matthew uniquely identifies Joseph as wealthy, possibly evoking Isa 53:9 (<em>kai dōsō tous ponērous anti tēs taphēs autou kai tous plousious anti tou thanatou autou</em> = with the rich at his death). <em>Tounoma Iōsēph hos kai autos emathēteuthē tō̄ Iēsou</em> (named Joseph, who also himself was discipled to Jesus) — <em>mathēteuō</em> (to make a disciple of, to disciple) passive: had become a disciple.</p>",
    "58": "<p><strong>houtos prosēlthen tō̄ Pilatō̄ ē̄tēsato to sōma tou Iēsou</strong> — <em>this one approaching Pilate asked for the body of Jesus</em> — <em>Ē̄tēsato</em> (aorist middle of <em>aitō</em> = asked for himself, requested) — the legal petition for the body of an executed criminal. Roman practice was to leave crucified bodies on the cross; relatives or disciples could request burial. <em>Tote ho Pilatos ekeleusen apodothēnai</em> (then Pilate commanded it to be given up).</p>",
    "59": "<p><strong>kai labōn to sōma ho Iōsēph enetylixen auto sindoni kathara</strong> — <em>Joseph taking the body wrapped it in a clean linen cloth</em> — <em>Sindōn</em> (fine linen cloth, shroud) — a single piece of linen. <em>Kathara</em> (clean, pure) — ritual cleanliness for burial cloth. The verb <em>enetylixen</em> (wrapped, wound around — from <em>entylissō</em>) describes the wrapping of the corpse for burial.</p>",
    "60": "<p><strong>kai ethēken auto en tō̄ kainō̄ autou mnēmeiō̄ ho elalatōmēsen en tē̄ petra</strong> — <em>placed it in his own new tomb which he had cut from the rock</em> — <em>Kainō̄</em> (new, unused — of a kind not previously used) — the newness is significant: no one else had yet been interred there, preventing confusion. <em>Elalatōmēsen en tē̄ petra</em> (had carved out from the rock) — rock-cut tombs in the Judean limestone hills; Joseph\xe2\x80\x99s own prepared tomb. <em>Kai proskyliesas lithon megan tē̄ thyra</em> (rolling a large stone to the door).</p>",
    "61": "<p><strong>ēn de ekei Mariam hē Magdalēnē kai hē allē Maria kathēmenai apenanti tou taphou</strong> — <em>Mary Magdalene and the other Mary were there sitting opposite the tomb</em> — <em>Kathēmenai apenanti</em> (sitting opposite/in front of) — the two women maintain vigil at the tomb entrance, observing the burial location. Their presence ensures the resurrection witnesses know exactly which tomb is at issue.</p>",
    "62": "<p><strong>tē̄ de epaurion hētis estin meta tēn paraskeuēn synēchthēsan hoi archiereis kai hoi Pharisaioi</strong> — <em>the next day which is after the Preparation the chief priests and Pharisees were assembled</em> — <em>Paraskeuē</em> (Preparation day = Friday, the day before Sabbath). The Sabbath-day meeting with Pilate underscores the urgency; Pharisees are now mentioned for the first time in the Passion narrative.</p>",
    "63": "<p><strong>kyrie emnēsthēmen hoti ekeinos ho planos eipen eti zōn</strong> — <em>lord, we remembered that this deceiver said while still living</em> — <em>Planos</em> (deceiver, impostor — from <em>planaō</em> = to lead astray) — the leaders apply the deception vocabulary to Jesus. <em>Meta treis hēmeras egeiromai</em> (after three days I will rise) — their memory of the resurrection prediction is precise; the disciples, by contrast, do not understand it until after the fact.</p>",
    "64": "<p><strong>keleuson oun asphalisthēnai ton taphon heōs tēs tritēs hēmeras</strong> — <em>command therefore the tomb to be secured until the third day</em> — <em>Asphalizō</em> (to make secure, seal fast — from <em>a</em> + <em>sphallō</em> = without stumbling/faltering) — an official seal to prevent tampering. <em>Mēpote elthontes hoi mathētai autou klepsōsin auton</em> (lest coming his disciples steal him) — the anticipated deception is a stolen body, not a resurrection.</p>",
    "65": "<p><strong>ephē autois ho Pilatos echete koustōdian</strong> — <em>Pilate said: you have a guard</em> — <em>Koustōdia</em> (guard — from Latin <em>custodia</em>) = a Roman military guard detail. <em>Echete</em> (you have) may be imperative (go ahead, take a guard) or indicative (you have the guard available). <em>Hypagete asphalisasthe hōs oidate</em> (go, make it secure as you know how).</p>",
    "66": "<p><strong>hoi de poreuthentes ēsphalisanto ton taphon sphragisantes ton lithon meta tēs koustōdias</strong> — <em>they went and secured the tomb sealing the stone with the guard</em> — <em>Sphragizō</em> (to seal — affixing an official clay/wax seal across the stone-door joint, so any tampering would be immediately evident). <em>Meta tēs koustōdias</em> (with the guard) — seal plus military guard provides maximum security, making the resurrection\xe2\x80\x99s impossibility-by-human-means unmistakable.</p>"
  },
  "28": {
    "1": "<p><strong>opse de sabbatōn tē̄ epiphōskousē̄ eis mian sabbatōn</strong> — <em>after the Sabbath at the dawning toward the first day of the week</em> — <em>Opse sabbatōn</em> (after the Sabbath — <em>opse</em> = late in, after; genitive of time) — Saturday evening after sunset, the beginning of Sunday in Jewish reckoning. <em>Tē̄ epiphōskousē̄</em> (at the dawning, as it began to light) — present participle of <em>epiphōskō</em> (to dawn upon, to begin to shine). <em>Eis mian sabbatōn</em> (toward the first day of the week) = Sunday.</p>",
    "2": "<p><strong>kai idou seismos egeneto megas</strong> — <em>and behold a great earthquake occurred</em> — <em>Seismos megas</em> (great earthquake) — the second earthquake of the Passion narrative (cf. 27:51). <em>Angelos gar kyriou katabas ex ouranou kai proselthōn apekylisenτον lithon</em> (for an angel of the Lord descending from heaven came and rolled away the stone) — <em>apokyliō</em> (to roll away from) — the stone is removed not to let Jesus out but to let witnesses in.</p>",
    "3": "<p><strong>ēn de hē eidea autou hōs astrapē kai to endyma autou leukon hōs chiōn</strong> — <em>his appearance was like lightning and his clothing white as snow</em> — <em>Eidea</em> (appearance, form — related to <em>eidon</em> = to see) — the visible aspect. <em>Astrapē</em> (lightning) and <em>chiōn</em> (snow) are both extreme-brightness comparisons. The angel\xe2\x80\x99s appearance echoes the Transfiguration\xe2\x80\x99s luminosity (17:2).</p>",
    "4": "<p><strong>apo de tou phobou autou eseisthēsan hoi tēroūntes kai egenēthēsan hōs nekroi</strong> — <em>from fear of him the guards shook and became as dead men</em> — <em>Eseisthēsan</em> (shook, the earthquake verb applied to persons) — the guards experience the same shaking as the earth. <em>Hōs nekroi</em> (as dead men) — the irony: the guards appointed to prevent resurrection become death-like while the dead one lives.</p>",
    "5": "<p><strong>apokritheis de ho angelos eipen tais gynaixin</strong> — <em>the angel answering said to the women</em> — <em>Apokritheis</em> (answering — the Semitic convention for beginning speech; the women have not spoken, but the angel responds to their evident state). <em>Mē phobeisthe hymeis</em> (do not be afraid, you) — the <em>hymeis</em> (you) is emphatic contrast: the guards have collapsed in fear, but the women need not fear.</p>",
    "6": "<p><strong>ouk estin hōde ēgerthē gar kathōs eipen</strong> — <em>he is not here; for he was raised as he said</em> — <em>Ouk estin hōde</em> (he is not here) — the negative declaration of absence precedes the positive declaration of resurrection. <em>Ēgerthē</em> (aorist passive: was raised) — divine passive; God raised him. <em>Kathōs eipen</em> (as he said) — the resurrection vindicates and fulfills the predictions of 16:21; 17:23; 20:19; 26:32. <em>Deute idete ton topon</em> (come see the place) — invitation to verify the empty tomb.</p>",
    "7": "<p><strong>kai tachy poreuthesai eipate tois mathētais autou hoti ēgerthē apo tōn nekrōn</strong> — <em>and go quickly and tell his disciples that he was raised from the dead</em> — <em>Tachy</em> (quickly, at once) — urgency. <em>Ēgerthē apo tōn nekrōn</em> (was raised from the dead) — the full resurrection formula. <em>Kai idou proagei hymas eis tēn Galilaian</em> (and behold he goes before you to Galilee) — fulfilling 26:32; <em>ekei auton opsesthe</em> (there you will see him) — the Galilean appearance is promised.</p>",
    "8": "<p><strong>kai apelthousai tachy apo tou mnēmeiou meta phobou kai charas megalēs</strong> — <em>leaving quickly from the tomb with fear and great joy</em> — The paradoxical combination <em>phobou kai charas</em> (fear and joy) is simultaneously true: the awesome reality of the angel and the empty tomb produces fear; the message of resurrection produces joy. <em>Edramon apangelai tois mathētais autou</em> (they ran to announce to his disciples).</p>",
    "9": "<p><strong>kai idou Iēsous hypēntēsen autais legōn chairete</strong> — <em>and behold Jesus met them saying: rejoice/greetings</em> — <em>Hypantaō</em> (to meet, encounter) — the risen Jesus meets the women before they reach the disciples. <em>Chairete</em> (rejoice, hail, greetings — the standard Greek greeting, but here charged with new meaning: the resurrection joy). <em>Hai de proselthousai ekratēsan autou tous podas kai prosekynēsan autō̄</em> (approaching they grasped his feet and worshiped him).</p>",
    "10": "<p><strong>tote legei autais ho Iēsous mē phobeisthe</strong> — <em>then Jesus says to them: do not be afraid</em> — The same formula as the angel (v.5); Jesus repeats the assurance. <em>Hypagete apangelate tois adelphois mou</em> (go announce to my brothers) — <em>adelphois</em> (brothers) — Jesus calls the disciples <em>brothers</em> for the first time in Matthew, a post-resurrection relational redefinition. <em>Hina apelthōsin eis tēn Galilaian kakei me opsontai</em>.</p>",
    "11": "<p><strong>poreuomenōn de autōn idou tines tēs koustōdias elthontes eis tēn polin apēngeilan tois archiereusin</strong> — <em>while they were going some of the guard coming into the city announced to the chief priests</em> — <em>Tines tēs koustōdias</em> (some of the guard) — not all; some go to the chief priests with their report. The guards\xe2\x80\x99 report to Jewish leaders rather than Roman authorities suggests they were Jewish temple police rather than Roman soldiers, or that they understood the political implications.</p>",
    "12": "<p><strong>kai synagentes meta tōn presbyterōn symboulion te labontes argyria hikana edōkan tois stratiōtais</strong> — <em>assembling with the elders and taking counsel they gave a sufficient sum of silver to the soldiers</em> — <em>Hikana</em> (sufficient, adequate — a commercial term) argyria (silver coins) — a bribe. <em>Symboulion labontes</em> (taking counsel) — the same deliberative term as 27:1; the leaders respond to the resurrection report with another conspiracy.</p>",
    "13": "<p><strong>legontes eipate hoti hoi mathētai autou nyktos elthontes eklepsan auton</strong> — <em>saying: say that his disciples coming by night stole him</em> — The counter-narrative requires the soldiers to admit sleeping on duty (a capital offense in Roman military law), making the story implausible on its face — sleeping guards could not know who stole the body. The leaders must promise to protect the soldiers (v.14) precisely because the story is self-incriminating.</p>",
    "14": "<p><strong>kai ean akousthē̄ touto epi tou hēgemonos hēmeis peisomen kai hymas amerim nous poiēsomen</strong> — <em>and if this is heard before the governor we will persuade him and keep you free from anxiety</em> — <em>Peisomen</em> (we will persuade) — the leaders accept responsibility for managing Pilate if the story reaches him. <em>Amerim nous</em> (free from anxiety, without care — from <em>a</em> + <em>merimna</em> = worry) — a legal promise of indemnity.</p>",
    "15": "<p><strong>hoi de labontes ta argyria epoiēsan hōs edidachthēsan</strong> — <em>taking the silver they did as they were taught</em> — <em>Edidachthēsan</em> (were taught/instructed — aorist passive of <em>didaskō</em>) — the soldiers are given a narrative and instructed to propagate it. <em>Kai diephēmisthē ho logos houtos para Ioudaiois mechri tēs sēmeron</em> (and this story was spread among Jews until today) — <em>diaphēmizō</em> (to spread a report throughout) — a contemporary apologetic note.</p>",
    "16": "<p><strong>hoi de hendeka mathētai eporeuthēsan eis tēn Galilaian eis to oros hou etaxato autois ho Iēsous</strong> — <em>the eleven disciples went to Galilee to the mountain where Jesus had directed them</em> — <em>Hendeka</em> (eleven) — the number after Judas\xe2\x80\x99s death. <em>Eis to oros</em> (to the mountain) — significant mountain encounters throughout Matthew (5:1; 17:1; 24:3); the final commission on a mountain echoes the Sinai covenant. <em>Hou etaxato autois</em> (where he had appointed/directed them — <em>tassō</em> = to arrange, appoint, a military/administrative term).</p>",
    "17": "<p><strong>kai idontes auton prosekynēsan hoi de edistasan</strong> — <em>seeing him they worshiped but some doubted</em> — <em>Prosekynēsan</em> (worshiped, full prostration) — the climactic act. <em>Hoi de edistasan</em> (but some doubted) — <em>distazō</em> (to hesitate, to be of two minds — from <em>dis</em> = twice; to be pulled in two directions). The honest acknowledgment of doubt among the worshipers is remarkable; the commission is given despite/to the doubters.</p>",
    "19": "<p><strong>poreuthentes oun mathēteusate panta ta ethnē</strong> — <em>going therefore disciple all the nations</em> — <em>Mathēteusate</em> (aorist imperative of <em>mathēteuō</em> = to make disciples) is the main verb; <em>poreuthentes</em> (going), <em>baptizōntes</em> (baptizing), and <em>didaskontes</em> (teaching) are participles supporting the main command. <em>Panta ta ethnē</em> (all the nations) — universal scope completing 24:14. <em>Baptizōntes autous eis to onoma tou patros kai tou huiou kai tou hagiou pneumatos</em> — the Trinitarian formula, unique in Matthew; <em>onoma</em> (name, singular) with three persons.</p>"
  }
}

